// OAuth2 Implicit Flow Implementation
class OAuth2Client {
  constructor(config) {
    this.clientId = config.clientId;
    this.redirectUri = config.redirectUri;
    this.authorizationEndpoint = config.authorizationEndpoint;
    this.scopes = config.scopes || ['openid'];
    this.state = this.generateState();
  }

  generateState() {
    return btoa(Math.random().toString(36).substring(2, 15) + Math.random().toString(36).substring(2, 15));
  }

  async authenticate() {
    // Validate redirect URI
    if (!this.isValidRedirectUri(this.redirectUri)) {
      throw new Error('Invalid redirect URI');
    }

    // Build authorization URL
    const params = new URLSearchParams({
      response_type: 'token',
      client_id: this.clientId,
      redirect_uri: this.redirectUri,
      scope: this.scopes.join(' '),
      state: this.state
    });

    const authUrl = `${this.authorizationEndpoint}?${params.toString()}`;
    
    // Redirect to authorization endpoint
    window.location.href = authUrl;
  }

  parseTokenFromFragment() {
    const fragment = window.location.hash.substring(1);
    const params = new URLSearchParams(fragment);
    
    // Validate state parameter
    const receivedState = params.get('state');
    if (receivedState !== this.state) {
      throw new Error('Invalid state parameter');
    }

    // Extract access token
    const accessToken = params.get('access_token');
    const tokenType = params.get('token_type') || 'Bearer';
    const expiresIn = params.get('expires_in');
    
    // Validate token exists
    if (!accessToken) {
      throw new Error('No access token found in URL fragment');
    }

    // Validate token is not empty
    if (accessToken.trim() === '') {
      throw new Error('Empty access token');
    }

    // Clear fragment from URL
    window.location.hash = '';

    return {
      accessToken,
      tokenType,
      expiresIn: expiresIn ? parseInt(expiresIn) : null
    };
  }

  isValidRedirectUri(uri) {
    try {
      const url = new URL(uri);
      return url.origin === window.location.origin;
    } catch (e) {
      return false;
    }
  }

  // Secure token storage using sessionStorage
  storeToken(tokenData) {
    try {
      // Validate token data
      if (!tokenData || !tokenData.accessToken) {
        throw new Error('Invalid token data');
      }

      // Store in sessionStorage (secure, not persistent)
      const tokenInfo = {
        accessToken: tokenData.accessToken,
        tokenType: tokenData.tokenType,
        expiresIn: tokenData.expiresIn,
        timestamp: Date.now()
      };

      sessionStorage.setItem('oauth_token', JSON.stringify(tokenInfo));
      return true;
    } catch (error) {
      console.error('Failed to store token:', error);
      return false;
    }
  }

  // Retrieve token from secure storage
  getStoredToken() {
    try {
      const tokenData = sessionStorage.getItem('oauth_token');
      if (!tokenData) return null;

      const parsed = JSON.parse(tokenData);
      
      // Validate token is not expired
      if (parsed.expiresIn && (Date.now() - parsed.timestamp) > (parsed.expiresIn * 1000)) {
        this.clearStoredToken();
        return null;
      }

      return parsed;
    } catch (error) {
      console.error('Failed to retrieve token:', error);
      return null;
    }
  }

  clearStoredToken() {
    sessionStorage.removeItem('oauth_token');
  }

  // Check if user is authenticated
  isAuthenticated() {
    return !!this.getStoredToken();
  }
}

// Initialize OAuth client
const oauthClient = new OAuth2Client({
  clientId: 'your-client-id',
  redirectUri: 'http://localhost:3000/callback',
  authorizationEndpoint: 'https://your-auth-server.com/oauth/authorize',
  scopes: ['openid', 'profile']
});

// Handle callback
if (window.location.pathname === '/callback') {
  try {
    const tokenData = oauthClient.parseTokenFromFragment();
    oauthClient.storeToken(tokenData);
    
    // Redirect to main app
    window.location.href = '/';
  } catch (error) {
    console.error('Authentication failed:', error);
    // Redirect to error page or login
    window.location.href = '/login?error=auth_failed';
  }
}

// React component for authentication
const AuthButton = () => {
  const handleLogin = () => {
    oauthClient.authenticate();
  };

  return (
    <button onClick={handleLogin}>
      Login with OAuth
    </button>
  );
};

// Protected route component
const ProtectedRoute = ({ children }) => {
  const isAuthenticated = oauthClient.isAuthenticated();
  
  if (!isAuthenticated) {
    return <div>Please login first</div>;
  }
  
  return children;
};

